lass="label">Descrição</label><textarea class="field" name="description" rows="3" x-model="form.description"></textarea></div></div><div class="border-t p-4"><button class="btn-primary w-full" x-text="mode==='edit'?'Salvar produto':'Cadastrar produto'"></button></div></form></div>@endif
