    <script>function shopManager(storeUrl,initial){const empty=()=>({id:'',name:'',description:'',price:'',stock:0,active:'1',image_url:null,action:storeUrl});const hasErrors=Boolean(initial?.hasErrors);return{modal:hasErrors,viewer:false,viewerProduct:empty(),mode:hasErrors?initial.mode:'create',form:hasErrors?initial.form:empty(),init(){if(this.modal)document.body.classList.add('overflow-hidden')},formatPrice(value){return new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}).format(Number(value)||0)},newProduct(){this.mode='create';this.form=empty();this.open()},viewProduct(p){this.viewerProduct={...p,active:String(p.active)};this.viewer=true;document.body.classList.add('overflow-hidden')},editViewedProduct(){const product={...this.viewerProduct};this.closeViewer();this.editProduct(product)},editProduct(p){this.mode='edit';this.form={...p,active:String(p.active)};this.open()},open(){this.modal=true;document.body.classList.add('overflow-hidden')},close(){this.modal=false;document.body.classList.remove('overflow-hidden')},closeViewer(){this.viewer=false;document.body.classList.remove('overflow-hidden')},closeAll(){if(this.modal)this.close();if(this.viewer)this.closeViewer()}}}</script>
